   371→// ExportDB opens a save dialog and exports the database using SQLite's VACUUM INTO
   372→// for a consistent online snapshot without interrupting the live connection.
   373→func (a *App) ExportDB() (string, error) {
   374→	dest, err := runtime.SaveFileDialog(a.ctx, runtime.SaveDialogOptions{
   375→		Title:           "データをバックアップ",
   376→		DefaultFilename: "atena-backup.db",
   377→		Filters: []runtime.FileFilter{
   378→			{DisplayName: "SQLiteデータベース (*.db)", Pattern: "*.db"},
   379→		},
   380→	})
   381→	if err != nil || dest == "" {
   382→		return "", nil
   383→	}
   384→	// 既存ファイルを一旦削除しないと VACUUM INTO が失敗する
   385→	_ = os.Remove(dest)
   386→	if _, err := a.db.ExecContext(a.ctx, "VACUUM INTO ?", dest); err != nil {
   387→		return "", fmt.Errorf("ExportDB: %w", err)
   388→	}
   389→	return dest, nil
   390→}
   391→
   392→// ImportDB opens a file dialog and atomically replaces the database file.
   393→// Returns true if the import was performed, false if the user cancelled.
   394→// The application must be restarted for the new DB to take effect.
   395→func (a *App) ImportDB() (bool, error) {
   396→	src, err := runtime.OpenFileDialog(a.ctx, runtime.OpenDialogOptions{
   397→		Title: "バックアップから復元",
   398→		Filters: []runtime.FileFilter{
   399→			{DisplayName: "SQLiteデータベース (*.db)", Pattern: "*.db"},
   400→		},
   401→	})
   402→	if err != nil || src == "" {
   403→		return false, nil
   404→	}
   405→	// 一時ファイルに書き出してからアトミックにリネーム (src == dbPath でも安全)
   406→	tmp := a.dbPath + ".import.tmp"
   407→	if err := copyFile(src, tmp); err != nil {
   408→		return false, fmt.Errorf("ImportDB コピー失敗: %w", err)
   409→	}
   410→	if err := os.Rename(tmp, a.dbPath); err != nil {
   411→		_ = os.Remove(tmp)
   412→		return false, fmt.Errorf("ImportDB 配置失敗: %w", err)
   413→	}
   414→	return true, nil
   415→}
   416→
   417→func copyFile(src, dst string) error {
   418→	in, err := os.Open(src)
   419→	if err != nil {
   420→		return err
   421→	}
   422→	defer in.Close()
   423→	out, err := os.Create(dst)
   424→	if err != nil {
   425→		return err
   426→	}
   427→	defer out.Close()
   428→	if _, err := io.Copy(out, in); err != nil {
   429→		return err
   430→	}
   431→	return out.Sync()
   432→}
