      <div>
        <p className="text-xs font-medium text-gray-700 mb-1">書字方向</p>
        <div className="flex rounded border border-gray-300 overflow-hidden text-xs">
          {(['vertical', 'horizontal'] as const).map((o) => (
            <button
              key={o}
