              style={{
                position: 'absolute',
                right: 0,
                bottom: 0,
                width: 10,
                height: 10,
                background: box.color,
                cursor: 'nwse-resize',
                opacity: 0.85,
              }}
            />
          </div>
        )
      })}
    </>
  )
}

